package com.carlib.api.config;
import com.carlib.api.event.CarLibEventBus;import java.io.IOException;import java.nio.file.*;import java.util.Map;import java.util.concurrent.ConcurrentHashMap;import java.util.function.Supplier;
public final class ConfigManager { public static final CarLibEventBus<ConfigChangedEvent> CONFIG_CHANGED = new CarLibEventBus<>(); private static final Map<ConfigFormat, ConfigCodec> CODECS = new ConcurrentHashMap<>(); private ConfigManager(){}
public static void registerCodec(ConfigCodec codec){CODECS.put(codec.format(), codec);} public static <T> T loadOrCreate(Path path, Class<T> type, Supplier<T> defaults, ConfigFormat format){ConfigCodec codec=requireCodec(format); if(Files.notExists(path)){T def=defaults.get(); save(path,def,type,format); return def;} try{return codec.decode(Files.readString(path), type);}catch(IOException e){throw new IllegalStateException("Failed to load config at "+path,e);} }
public static <T> void save(Path path, T value, Class<T> type, ConfigFormat format){ConfigCodec codec=requireCodec(format); try{Path parent=path.getParent(); if(parent!=null) Files.createDirectories(parent); Files.writeString(path, codec.encode(value,type)); CONFIG_CHANGED.post(new ConfigChangedEvent(path.toString()));}catch(IOException e){throw new IllegalStateException("Failed to save config at "+path,e);} }
private static ConfigCodec requireCodec(ConfigFormat format){ConfigCodec c=CODECS.get(format); if(c==null) throw new IllegalStateException("No codec registered for format "+format); return c;} }
